const payload = $input.first().json;
const msgs = payload.messages;
if (!msgs || !msgs.length) return [];
const msg = msgs[0];
if (msg.type !== 'text') return [];
const phone = msg.from || '';
const text = msg.text?.body?.trim() || '';
if (!phone || !text) return [];
const name = payload.contacts?.[0]?.profile?.name || '';
return [{ json: { phoneNumber: phone, messageText: text, pushName: name, conversationId: 'scala_' + phone, timestamp: new Date().toISOString() } }];

// Detect if Paulo (owner) is messaging
const { messageText, pushName, conversationId, phoneNumber, timestamp } = $('Extrair Dados').first().json;
const isPaulo = phoneNumber === '556181292879';

// Only inject meeting data when Paulo explicitly asks about it
const askingAboutMeetings = isPaulo && /reuni[aã]o?s?|agenda|diagn[oó]stico|marcamos|agendamos|agendou|marcou|hor[aá]rios?|quan(tos?|tas?)|hoje|semana|m[eê]s/i.test(messageText);

let meetingContext = '';
if (askingAboutMeetings) {
  try {
    const reunioesData = $('Buscar Reuniões').first().json;
    const eventos = (reunioesData.items || []).filter(e => e.start && e.start.dateTime);

    const agora = new Date();
    const hojeStr = new Date(agora.getTime() - 3 * 60 * 60 * 1000).toISOString().split('T')[0];
    const mesAtual = agora.getMonth();
    const anoAtual = agora.getFullYear();

    const getEventDateTime = (e) => new Date(e.start.dateTime);
    const getEventDate = (e) => new Date(e.start.dateTime - 3 * 60 * 60 * 1000).toISOString().split('T')[0];

    const reunioesMes = eventos.filter(e => {
      const d = getEventDateTime(e);
      return d.getMonth() === mesAtual && d.getFullYear() === anoAtual;
    });

    const reunioesHoje = reunioesMes.filter(e => getEventDate(e) === hojeStr);
    const reunioesPassadas = reunioesMes.filter(e => getEventDateTime(e) < agora);
    const reunioesProximas = reunioesMes.filter(e => getEventDateTime(e) >= agora);

    const formatEvento = (e) => {
      const dt = getEventDateTime(e);
      const data = dt.toLocaleDateString('pt-BR', {weekday:'short', day:'2-digit', month:'2-digit', timeZone:'America/Sao_Paulo'});
      const hora = dt.toLocaleTimeString('pt-BR', {hour:'2-digit', minute:'2-digit', timeZone:'America/Sao_Paulo'});
      return `  - ${data} às ${hora}: ${e.summary || 'Sem título'}`;
    };

    meetingContext = `\n<dados_reunioes>\nDATA DE HOJE: ${hojeStr}\n\nREUNIÕES HOJE: ${reunioesHoje.length === 0 ? 'nenhuma' : reunioesHoje.length}\n${reunioesHoje.map(formatEvento).join('\n')}\n\nMÊS ATUAL: ${reunioesMes.length} reunião(ões) no total | ${reunioesPassadas.length} realizadas | ${reunioesProximas.length} futuras\n\n${reunioesPassadas.length > 0 ? 'REALIZADAS NO MÊS:\n' + reunioesPassadas.map(formatEvento).join('\n') : 'Nenhuma realizada ainda este mês.'}\n\n${reunioesProximas.length > 0 ? 'PRÓXIMAS:\n' + reunioesProximas.slice(0, 5).map(formatEvento).join('\n') : 'Nenhuma futura agendada.'}\n</dados_reunioes>`;
  } catch(err) {
    meetingContext = '\n<dados_reunioes>Não foi possível carregar os dados da agenda neste momento.</dados_reunioes>';
  }
}

const allRows = $('Buscar Histórico').all();
const history = allRows
  .filter(item => item.json.conversationId === conversationId)
  .slice(-20)
  .map(item => ({ role: item.json.role, content: item.json.content }))
  .filter(m => m.role && m.content);
const slotData = $('Formatar Slots').first().json;
const busyText = slotData.busyText || 'nenhum compromisso';
const nextSlotsText = slotData.nextSlotsText || 'próximos dias';
const leadCtx = pushName ? ' O lead se chama ' + pushName + ' (nome do perfil do WhatsApp).' : '';

const historicoFormatado = history.map(m => `${m.role === 'user' ? 'Lead' : 'Ana'}: ${m.content}`).join('\n');

let systemPrompt;

if (isPaulo) {
  systemPrompt = `<modo_dono>
Você é a Ana, assistente executiva de Paulo, dono da Scala Automações.
Você NÃO está vendendo nada para Paulo — ele é o dono da empresa.
Trate Paulo como seu chefe direto: seja direta, objetiva e profissional.
</modo_dono>

<comportamento_com_paulo>
- Você é a assistente executiva de Paulo — responda de forma direta e objetiva, sem pitch de vendas
- Paulo pode perguntar sobre reuniões, agenda, clientes, métricas ou status de automações
- Quando Paulo perguntar sobre reuniões/agenda: use os dados em <dados_reunioes> se disponíveis. Responda com os números e detalhes exatos do que estiver lá.
- Se <dados_reunioes> não estiver presente na conversa: diga que não tem os dados da agenda disponíveis no momento
- NUNCA mencione reuniões, agenda ou dados de calendário se Paulo não perguntar sobre isso
- Tom: direto, como conversa entre profissionais que trabalham juntos
- Fale em português brasileiro natural, sem formalidade excessiva
</comportamento_com_paulo>

<empresa>
Scala Automações — agência de automação e marketing digital, Brasília/DF.
Dono: Paulo Nunan
Agentes ativos: Ana (atendimento 24/7) + Bruno (gestão de tráfego via WhatsApp)
Meta Ad Account: act_1605651367382391 (Scala-Conta-Anúncios)
Google Ads MCC: 4323799990
</empresa>

${meetingContext}

<historico_conversa>
${historicoFormatado}
</historico_conversa>`;
} else {
  systemPrompt = '<identidade>Você é a Ana, consultora de automação da Scala. Você NAO é um chatbot. Você é uma profissional de consultoria especializada em marketing digital, tráfego pago e automação de vendas.</identidade><empresa>A Scala é uma empresa de infraestrutura digital para ecossistemas de vendas. Posicionamento: estruturamos o caminho entre o lead e o fechamento. Público-alvo: gestores de tráfego, agências e donos de negócios que investem em tráfego pago. Fundada por profissional com 5 anos em marketing digital especializado em funis de vendas e automação.</empresa><servicos>1. RELATÓRIOS INTELIGENTES - Dashboards automáticos + PDF no WhatsApp do gestor. A partir de R$ 300/mês. 2. CRM AUTOMATIZADO - O CRM se alimenta sozinho com dados dos leads. A partir de R$ 400/mês. 3. QUALIFICAÇÃO DE LEADS - IA que pontua e prioriza leads automaticamente. A partir de R$ 400/mês. 4. FOLLOW-UP COM IA - Sequências automáticas e contextuais que recuperam leads sumidos. A partir de R$ 350/mês. 5. ATENDIMENTO IA 24/7 - Agente de IA que responde, qualifica e agenda reuniões 24 horas por dia. A partir de R$ 500/mês por operação. 6. AUTOMAÇÃO DE ADS - Regras automáticas para campanhas e alertas de performance. A partir de R$ 450/mês. Preços são referencias e o valor final depende do escopo.</servicos><pacotes>STARTER: Relatórios + CRM, a partir de R$ 600/mês. PRO mais popular: Starter + Atendimento IA 24/7 + Qualificação + Follow-up, a partir de R$ 1.500/mês. ENTERPRISE: Pro + Automação de Ads + Consultoria + SLA dedicado, sob consulta. Nao mencione pacotes proativamente, só se o lead perguntar diretamente.</pacotes><tom_de_voz>REGRAS ABSOLUTAS: 1. SEJA HUMANA - escreva como pessoa real no WhatsApp, frases curtas, sem formalidade. 2. SEJA DIRETA - proibido saudações corporativas como Olá seja bem-vindo. 3. PORTUGUÊS NATURAL - use: tá, pra, né, show, massa, entendo demais. 4. VARIE O COMPRIMENTO - de uma frase a 3-4 frases, nunca textão. 5. FAÇA PERGUNTAS - termine preferencialmente cada mensagem com uma pergunta. 6. SEM BULLET POINTS - fale como numa conversa normal, nao como relatório. 7. MAXIMO 1 EMOJI por mensagem e só quando for natural. 8. NUNCA diga que é IA, chatbot ou assistente virtual. 9. USE O NOME do lead quando souber, naturalmente. 10. DEMONSTRE EXPERTISE em tráfego pago, CPA, ROAS, funil de vendas, CRM, LTV.</tom_de_voz><metodologia>SPIN Selling adaptado para WhatsApp: SITUAÇÃO (quantos leads por mês, quem atende hoje, qual ferramenta usa); PROBLEMA (perde leads por demora no atendimento, sem visibilidade dos resultados, sem qualificação automática); IMPLICAÇÃO (amplifique com dados: se recebe 200 leads e 40% nao sao atendidos em tempo, sao 80 oportunidades perdidas por mês); NECESSIDADE (faça o lead verbalizar que precisa de solução). Use como bússola, nao como script fixo.</metodologia><qualificacao>Colete naturalmente ao longo da conversa sem parecer formulário. ESSENCIAIS sem isso nao agende: nome, tipo de negócio, principal dor. DESEJÁVEIS se a conversa permitir: volume de leads por mês, ferramentas que usa, investimento mensal em tráfego, urgência. QUENTE tem dor clara mais volume mais urgência, agendar imediatamente. MORNO tem interesse sem urgência definida, agendar sem pressão. FRIO só curiosidade sem dor clara, educar e manter porta aberta.</qualificacao><agendamento>OBJETIVO PRINCIPAL: agendar DIAGNÓSTICO GRATUITO de 15-20 minutos por videochamada Google Meet. VOCÊ TEM ACESSO À AGENDA REAL. COMPROMISSOS JÁ MARCADOS (períodos ocupados): ' + busyText + '. PRÓXIMAS DISPONIBILIDADES PARA SUGERIR: ' + nextSlotsText + '. REGRAS: 1. Para propor: cite 2-3 das próximas disponibilidades. 2. SE O LEAD CONFIRMAR OU PROPUSER UM HORÁRIO: verifique APENAS se conflita com os períodos ocupados listados acima. Se NÃO conflita: CONFIRME IMEDIATAMENTE. Não invente ocupações que não estão na lista. 3. Se conflita: proponha o slot mais próximo disponível. 4. Confirmação: Perfeito! [dia] às [hora] tá confirmado. Vou te mandar o link do Google Meet agora. 5. NUNCA repita a pergunta de horário se o lead já confirmou um. 6. Após confirmar, diga que vai enviar o link e encerre de forma calorosa.</agendamento><ligacoes>APENAS se o lead pedir explicitamente para ligar, telefonar ou pedir numero de telefone (frases como quero ligar, pode me ligar, me passa o telefone, prefiro falar por ligacao): redirecione naturalmente para o WhatsApp ou Google Meet. Exemplos: Por aqui mesmo consigo te atender melhor e mais rápido. Que tal a gente marcar um Google Meet de 15 minutos?; Fica mais fácil resolver tudo por aqui. Se quiser algo mais detalhado, bora marcar um papo por videochamada. NUNCA use esta instrução quando o lead pedir uma reunião, diagnóstico ou agendamento — nesses casos vá direto para o fluxo de agendamento.</ligacoes><objecoes>É caro ou sem orçamento: Entendo. Quanto você investe por mês em tráfego pago? O custo de perder leads por atendimento lento geralmente é maior que a automação. Já tentei chatbot: A maioria dos chatbots é baseada em fluxo fixo. A Scala usa IA conversacional que entende contexto e responde como pessoa real. Preciso pensar: Claro, sem pressa. O diagnóstico é gratuito e sem compromisso, você sai com mapa claro do gargalo independente de fechar. Faz sentido marcar? Já uso ferramenta X: Ela está integrada com WhatsApp? Qualificando leads automaticamente? Gerando relatório sozinha? Quanto custa exatamente: Depende do escopo. Serviços individuais a partir de R$ 300/mês, pacotes a partir de R$ 600/mês. No diagnóstico te dou o número preciso pro seu caso.</objecoes><limites>NUNCA: invente informações sobre a Scala; fale mal de concorrentes; prometa resultados específicos como triplicar vendas; discuta política, religião ou futebol; feche vendas pelo WhatsApp pois objetivo é SEMPRE agendar; mande links externos exceto o site https://scala-kappa.vercel.app/; peça dados sensíveis como CPF ou dados bancários.</limites><dados_mercado>Use com moderação, um dado por conversa no momento certo: empresas que respondem em até 5 minutos têm 21x mais chance de qualificar o lead; 78% dos clientes compram do primeiro que responde; tempo médio de resposta brasileiro é 4 horas; 40% dos leads de tráfego pago sao perdidos por falha no atendimento.</dados_mercado><horario>Entre 8h e 22h horário de Brasília responda normalmente. Entre 22h e 8h responda normalmente pois você é atendimento 24/7 mas seja mais conciso e sugira continuar a conversa mais detalhada no dia seguinte se necessário. Nunca mencione estar fora do horário comercial.</horario>' + leadCtx;
}

const requestBody = {
  model: 'gpt-4o-mini',
  max_tokens: 300,
  temperature: 0.7,
  messages: [{ role: 'system', content: systemPrompt }, ...history, { role: 'user', content: messageText }]
};
return [{ json: { requestBody, conversationId, phoneNumber, originalMessage: messageText, pushName, timestamp } }];

const aiResponse = $input.first().json.choices?.[0]?.message?.content || '';
const ctx = $('Montar Contexto').first().json;
return [{ json: { aiResponse, phoneNumber: ctx.phoneNumber, conversationId: ctx.conversationId, originalMessage: ctx.originalMessage, pushName: ctx.pushName, timestamp: new Date().toISOString() } }];

try {
  const BRT_MS = 3 * 3600 * 1000; // Brasília = UTC-3
  const utcNow = new Date();
  // brNow: Date onde campos UTC = horário local Brasília
  const brNow = new Date(utcNow.getTime() - BRT_MS);

  let busyPeriods = [];
  try {
    const calData = $input.first().json;
    busyPeriods = calData.calendars?.primary?.busy || [];
  } catch(e) {}

  const busy = busyPeriods.map(b => ({
    startUtc: new Date(b.start).getTime(),
    endUtc: new Date(b.end).getTime()
  }));

  const dayNames = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];
  const pad = n => String(n).padStart(2, '0');

  // Formatar períodos ocupados (horário Brasília)
  const busyText = busy.length > 0
    ? busy.map(b => {
        const startBr = new Date(b.startUtc - BRT_MS);
        const endBr = new Date(b.endUtc - BRT_MS);
        return dayNames[startBr.getUTCDay()] + ' ' + pad(startBr.getUTCDate()) + '/' + pad(startBr.getUTCMonth()+1) + ' ' + pad(startBr.getUTCHours()) + ':' + pad(startBr.getUTCMinutes()) + '-' + pad(endBr.getUTCHours()) + ':' + pad(endBr.getUTCMinutes());
      }).join(', ')
    : 'nenhum compromisso agendado esta semana';

  // Próximos slots livres (até 22h)
  const freeSlots = [];
  for (let d = 0; d < 7 && freeSlots.length < 6; d++) {
    const dayBr = new Date(brNow);
    dayBr.setUTCDate(dayBr.getUTCDate() + d);
    const wday = dayBr.getUTCDay(); // 0=Dom
    if (wday === 0) continue; // pular domingo
    const dayLabel = dayNames[wday] + ' ' + pad(dayBr.getUTCDate()) + '/' + pad(dayBr.getUTCMonth()+1);

    for (let h = 8; h <= 22; h++) {
      for (const m of [0, 30]) {
        if (freeSlots.length >= 6) break;
        const slotBr = new Date(dayBr);
        slotBr.setUTCHours(h, m, 0, 0);
        const slotUtcStart = slotBr.getTime() + BRT_MS; // Brasília → UTC
        const slotUtcEnd = slotUtcStart + 30 * 60 * 1000;
        if (slotUtcStart <= utcNow.getTime()) continue; // passado
        const isBusy = busy.some(b => slotUtcStart < b.endUtc && slotUtcEnd > b.startUtc);
        if (!isBusy) freeSlots.push(dayLabel + ' ' + pad(h) + ':' + pad(m));
      }
    }
  }

  const nextSlotsText = freeSlots.slice(0, 4).join(', ') || 'próximos dias úteis';
  return [{ json: { busyText, nextSlotsText, totalBusy: busy.length } }];
} catch(e) {
  return [{ json: { busyText: 'nenhum compromisso', nextSlotsText: 'dias úteis 8h-22h', totalBusy: 0 } }];
}

const BRT_MS = 3 * 3600 * 1000; // Brasília = UTC-3
const pad = n => String(n).padStart(2, '0');
const utcNow = new Date();
// brNow: campos UTC = horário local Brasília
const brNow = new Date(utcNow.getTime() - BRT_MS);

const aiResponse = $('Preparar Resposta').first().json.aiResponse;
const pushName = $('Preparar Resposta').first().json.pushName || 'Lead';
const phoneNumber = $('Preparar Resposta').first().json.phoneNumber;

// Extrair horário: HH:MM, HHhMM, HHh
const timeMatch = aiResponse.match(/(\d{1,2})[h:](\d{2})?(?!\d)/i);
const hour = timeMatch ? parseInt(timeMatch[1]) : 9;
const minute = (timeMatch && timeMatch[2]) ? parseInt(timeMatch[2]) : 0;

// Extrair data DD/MM
const dateMatch = aiResponse.match(/(\d{1,2})\/(\d{1,2})/);
const targetBr = new Date(brNow);

if (dateMatch) {
  const day = parseInt(dateMatch[1]);
  const month = parseInt(dateMatch[2]);
  targetBr.setUTCDate(day);
  targetBr.setUTCMonth(month - 1);
  if (targetBr.getTime() < brNow.getTime() - 3600*1000) {
    targetBr.setUTCFullYear(targetBr.getUTCFullYear() + 1);
  }
} else {
  const lower = aiResponse.toLowerCase();
  const brWeekday = brNow.getUTCDay(); // 0=Dom, 1=Seg, ...
  const weekdayMap = { 'segunda': 1, 'terça': 2, 'quarta': 3, 'quinta': 4, 'sexta': 5, 'sábado': 6 };
  if (lower.includes('hoje')) {
    // mantém data atual
  } else if (lower.includes('amanhã') || lower.includes('amanha')) {
    targetBr.setUTCDate(targetBr.getUTCDate() + 1);
  } else {
    for (const [kw, wd] of Object.entries(weekdayMap)) {
      if (lower.includes(kw)) {
        let diff = wd - brWeekday;
        if (diff <= 0) diff += 7;
        targetBr.setUTCDate(targetBr.getUTCDate() + diff);
        break;
      }
    }
  }
}

// Definir horário na data Brasília
targetBr.setUTCHours(hour, minute, 0, 0);

// Calcular endTime (+30 min)
const endHour = minute >= 30 ? hour + 1 : hour;
const endMinute = minute >= 30 ? 0 : 30;

// Formato ISO local para Google Calendar (com timeZone no body)
const startISO = targetBr.getUTCFullYear() + '-' + pad(targetBr.getUTCMonth()+1) + '-' + pad(targetBr.getUTCDate()) + 'T' + pad(hour) + ':' + pad(minute) + ':00';
const endISO = targetBr.getUTCFullYear() + '-' + pad(targetBr.getUTCMonth()+1) + '-' + pad(targetBr.getUTCDate()) + 'T' + pad(endHour) + ':' + pad(endMinute) + ':00';
const humanDate = pad(targetBr.getUTCDate()) + '/' + pad(targetBr.getUTCMonth()+1) + ' às ' + pad(hour) + ':' + pad(minute);
const requestId = 'scala-' + targetBr.getUTCFullYear() + pad(targetBr.getUTCMonth()+1) + pad(targetBr.getUTCDate()) + '-' + pad(hour) + pad(minute);

return [{
  json: {
    startISO,
    endISO,
    leadName: pushName,
    phoneNumber,
    requestId,
    summary: 'Diagnóstico Gratuito Scala - ' + pushName,
    humanDate
  }
}];

const ctx = $('Preparar Resposta').first().json;
const messages = $('Montar Contexto').first().json.requestBody.messages;

// Apenas user/assistant (sem system prompt)
const conv = messages.filter(m => m.role !== 'system');

// Precisa de pelo menos 2 trocas para extrair dados
if (conv.length < 2) return [];

const conversationText = conv
  .map(m => (m.role === 'user' ? 'Lead' : 'Ana') + ': ' + m.content)
  .join('\n');

const requestBody = {
  model: 'gpt-4o-mini',
  max_tokens: 150,
  temperature: 0,
  response_format: { type: 'json_object' },
  messages: [
    {
      role: 'system',
      content: 'Analise a conversa de vendas e retorne JSON com os campos: nome (nome do lead), negocio (tipo de empresa ou negócio), dor (principal problema ou dor mencionada), classificacao (QUENTE se dor clara e urgência, MORNO se interesse sem urgência, FRIO se só curiosidade, INDEFINIDO se sem dados), status (em_atendimento, agendado se reunião foi confirmada, perdido se desistiu), volume_leads (número de leads por mês mencionado ou vazio), investimento_trafego (valor mensal em tráfego mencionado ou vazio). Use string vazia quando não souber.'
    },
    {
      role: 'user',
      content: conversationText
    }
  ]
};

return [{
  json: {
    requestBody,
    phoneNumber: ctx.phoneNumber,
    pushName: ctx.pushName,
    conversationId: ctx.conversationId
  }
}];

const raw = $input.first().json.choices?.[0]?.message?.content || '{}';
const prep = $('CRM Preparar Request').first().json;

let profile = {};
try { profile = JSON.parse(raw); } catch(e) {}

// Formatar data para dd/MM/yyyy HH:mm em Brasília (UTC-3)
const BRT_MS = 3 * 3600 * 1000;
const pad = n => String(n).padStart(2, '0');
const formatBR = (isoStr) => {
  const br = new Date(new Date(isoStr).getTime() - BRT_MS);
  return pad(br.getUTCDate()) + '/' + pad(br.getUTCMonth()+1) + '/' + br.getUTCFullYear() + ' ' + pad(br.getUTCHours()) + ':' + pad(br.getUTCMinutes());
};

// Buscar data do primeiro contato no histórico
const allRows = $('Buscar Histórico').all();
const convRows = allRows
  .filter(r => r.json.conversationId === prep.conversationId && r.json.timestamp)
  .sort((a, b) => new Date(a.json.timestamp) - new Date(b.json.timestamp));
const firstContact = convRows.length > 0 ? convRows[0].json.timestamp : new Date().toISOString();

return [{
  json: {
    telefone: prep.phoneNumber,
    nome: profile.nome || prep.pushName || '',
    negocio: profile.negocio || '',
    dor: profile.dor || '',
    classificacao: profile.classificacao || 'INDEFINIDO',
    status: profile.status || 'em_atendimento',
    volume_leads: profile.volume_leads || '',
    investimento_trafego: profile.investimento_trafego || '',
    data_primeiro_contato: formatBR(firstContact),
    ultima_atualizacao: formatBR(new Date().toISOString())
  }
}];

const payload = $input.first().json;
const msgs = payload.messages;
if (!msgs || !msgs.length) return [];
const msg = msgs[0];
if (msg.type !== 'text') return [];
const phone = msg.from || '';
const text = msg.text?.body?.trim() || '';
if (!phone || !text) return [];
const name = payload.contacts?.[0]?.profile?.name || '';
return [{ json: { phoneNumber: phone, messageText: text, pushName: name, conversationId: 'scala_' + phone, timestamp: new Date().toISOString() } }];

// Detect if Paulo (owner) is messaging
const { messageText, pushName, conversationId, phoneNumber, timestamp } = $('Extrair Dados').first().json;
const isPaulo = phoneNumber === '556181292879';

// Only inject meeting data when Paulo explicitly asks about it
const askingAboutMeetings = isPaulo && /reuni[aã]o?s?|agenda|diagn[oó]stico|marcamos|agendamos|agendou|marcou|hor[aá]rios?|quan(tos?|tas?)|hoje|semana|m[eê]s/i.test(messageText);

let meetingContext = '';
if (askingAboutMeetings) {
  try {
    const reunioesData = $('Buscar Reuniões').first().json;
    const eventos = (reunioesData.items || []).filter(e => e.start && e.start.dateTime);

    const agora = new Date();
    const hojeStr = new Date(agora.getTime() - 3 * 60 * 60 * 1000).toISOString().split('T')[0];
    const mesAtual = agora.getMonth();
    const anoAtual = agora.getFullYear();

    const getEventDateTime = (e) => new Date(e.start.dateTime);
    const getEventDate = (e) => new Date(e.start.dateTime - 3 * 60 * 60 * 1000).toISOString().split('T')[0];

    const reunioesMes = eventos.filter(e => {
      const d = getEventDateTime(e);
      return d.getMonth() === mesAtual && d.getFullYear() === anoAtual;
    });

    const reunioesHoje = reunioesMes.filter(e => getEventDate(e) === hojeStr);
    const reunioesPassadas = reunioesMes.filter(e => getEventDateTime(e) < agora);
    const reunioesProximas = reunioesMes.filter(e => getEventDateTime(e) >= agora);

    const formatEvento = (e) => {
      const dt = getEventDateTime(e);
