const phoneNumber = $('Preparar Resposta').first().json.phoneNumber;

// Extrair horário: HH:MM, HHhMM, HHh
const timeMatch = aiResponse.match(/(\d{1,2})[h:](\d{2})?(?!\d)/i);
const hour = timeMatch ? parseInt(timeMatch[1]) : 9;
const minute = (timeMatch && timeMatch[2]) ? parseInt(timeMatch[2]) : 0;

// Extrair data DD/MM
const dateMatch = aiResponse.match(/(\d{1,2})\/(\d{1,2})/);
const targetBr = new Date(brNow);

if (dateMatch) {
  const day = parseInt(dateMatch[1]);
  const month = parseInt(dateMatch[2]);
  targetBr.setUTCDate(day);
  targetBr.setUTCMonth(month - 1);
  if (targetBr.getTime() < brNow.getTime() - 3600*1000) {
    targetBr.setUTCFullYear(targetBr.getUTCFullYear() + 1);
  }
} else {
  const lower = aiResponse.toLowerCase();
  const brWeekday = brNow.getUTCDay(); // 0=Dom, 1=Seg, ...
  const weekdayMap = { 'segunda': 1, 'terça': 2, 'quarta': 3, 'quinta': 4, 'sexta': 5, 'sábado': 6 };
  if (lower.includes('hoje')) {
    // mantém data atual
  } else if (lower.includes('amanhã') || lower.includes('amanha')) {
    targetBr.setUTCDate(targetBr.getUTCDate() + 1);
  } else {
    for (const [kw, wd] of Object.entries(weekdayMap)) {
      if (lower.includes(kw)) {
        let diff = wd - brWeekday;
        if (diff <= 0) diff += 7;
        targetBr.setUTCDate(targetBr.getUTCDate() + diff);
        break;
      }
    }
  }
}

// Definir horário na data Brasília
targetBr.setUTCHours(hour, minute, 0, 0);

// Calcular endTime (+30 min)
const endHour = minute >= 30 ? hour + 1 : hour;
const endMinute = minute >= 30 ? 0 : 30;

// Formato ISO local para Google Calendar (com timeZone no body)
const startISO = targetBr.getUTCFullYear() + '-' + pad(targetBr.getUTCMonth()+1) + '-' + pad(targetBr.getUTCDate()) + 'T' + pad(hour) + ':' + pad(minute) + ':00';
