const humanDate = pad(targetBr.getUTCDate()) + '/' + pad(targetBr.getUTCMonth()+1) + ' às ' + pad(hour) + ':' + pad(minute);
const requestId = 'scala-' + targetBr.getUTCFullYear() + pad(targetBr.getUTCMonth()+1) + pad(targetBr.getUTCDate()) + '-' + pad(hour) + pad(minute);

return [{
